export declare const AzureDiskStorageRules = "\n# Azure Disk Storage - WAF Rules for IaC\n\n- Use managed disks instead of unmanaged disks\n- Use premium SSD or ultra disks for production I/O intensive workloads\n- Configure zone-redundant storage (ZRS) for critical applications\n- Enable disk encryption at rest with platform or customer-managed keys\n- Link to Azure Key Vault for customer-managed encryption keys\n- Configure appropriate disk size and type based on performance needs\n- Enable disk bursting for variable workload patterns\n";
